function normText(s) {
  return String(s || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const recetario = {};
Object.entries(RECETARIO_DATA).forEach(([act, data]) => {
  recetario[act] = {
    categoria: data.categoria,
    materiales: data.materiales.map((m) => ({
      material: m.material,
      cantidad: m.cantidad,
      escala: m.escala,
      notas: m.notas || '',
      tipoUso: MATERIALES_REUTILIZABLES_DEFAULT.has(normText(m.material)) ? 'Reutilizable' : 'Consumible',
    })),
  };
});

const aliasActividades = ALIAS_ACTIVIDADES_DEFAULT.map(([variante, canonica]) => ({ variante, canonica }));

writeFileSync(path.join(dataDir, 'recetario.seed.json'), JSON.stringify(recetario, null, 2));
